249	/**
250	 * KRN-09 — kind of substitution applied to a curtain-wall grid cell.
251	 *
252	 * - `empty`: leave the cell open (no glass, no solid panel; mullions stay).
253	 * - `system`: render the cell as a solid panel using a registered
254	 *   `materialKey`. Falls back to glass if no `materialKey` is supplied.
255	 * - `family_instance`: instantiate a custom family at this cell. Until
256	 *   FAM-01 lands the renderer paints a placeholder panel and emits a TODO.
257	 */
258	export type CurtainPanelOverrideKind = 'empty' | 'system' | 'family_instance';
259	
260	export type CurtainPanelOverride = {
261	  kind: CurtainPanelOverrideKind;
262	  /** For `family_instance` overrides — id of the family type to instantiate. */
263	  familyTypeId?: string | null;
264	  /** For `system` overrides — `materialKey` resolved against the MAT-01 registry. */
265	  materialKey?: string | null;
266	};
