299	/**
300	 * FED-03: structured monitor-source pointer used by Copy/Monitor.
301	 *
302	 * `linkId` (when set) names a `link_model` element in the host whose source
303	 * model contains the monitored element; intra-host monitors omit it.
304	 * `elementId` is the **source-side** id (not the `<linkId>::<sourceElemId>`
305	 * prefixed form). `sourceRevisionAtCopy` is the source model's revision
306	 * counter at the moment of the copy; the BumpMonitoredRevisions command
307	 * compares it against the latest revision and flags drift.
308	 *
309	 * `drifted` and `driftedFields` are computed by BumpMonitoredRevisions; they
310	 * persist on the host element so the constraint evaluator can emit a
311	 * `monitored_source_drift` advisory without needing live source access.
312	 */
313	export type MonitorSource = {
314	  linkId?: string | null;
315	  elementId: string;
316	  sourceRevisionAtCopy: number;
317	  drifted?: boolean;
318	  driftedFields?: string[];
319	};
