/** FED-04: 2D linework primitive parsed from a DXF underlay. */
export type DxfLineworkPrim =
  | { kind: 'line'; start: XY; end: XY }
  | { kind: 'polyline'; points: XY[]; closed?: boolean }
  | {
      kind: 'arc';
