def try_commit_bundle(
    doc: Document,
    cmds_raw: list[dict[str, Any]],
    *,
    source_provider: SourceDocProvider | None = None,
) -> tuple[bool, Document | None, list[Command], list[Violation], str]:
    try:
        cmds: list[Command] = [coerce_command(c) for c in cmds_raw]
    except Exception as exc:
        return False, None, [], [], str(exc)
    cand = clone_document(doc)
    # KRN-06: backfill the singleton on every commit so persisted state always
    # has it (matches `try_commit`'s behaviour for the single-command path).
    ensure_internal_origin(cand)
    try:
        for cmd in cmds:
            apply_inplace(cand, cmd, source_provider=source_provider)
    except (ValueError, KeyError) as exc:
        return False, None, cmds, [], str(exc)

    ensure_sun_settings(cand)
    violations = evaluate(cand.elements)

    # EDT-02 — reject bundles that break an error-severity locked constraint.
    # Runs after every command apply; the clone rollback is implicit because
    # we never return ``cand`` on failure.
    edt_violations = _evaluate_edt_constraint_violations(cand.elements)
    violations = violations + edt_violations

    blocking = [v for v in violations if v.blocking or v.severity == "error"]
    if blocking:
        return False, None, cmds, violations, "constraint_error"

    cand.revision = doc.revision + 1

    _assert_tkn_round_trip(cand)

    return True, cand, cmds, violations, "ok"

    target = next((o for o in the_set.options if o.id == cmd.option_id), None)
    if target is None:
        raise ValueError(f"option not found: {cmd.option_id!r}")
    for o in the_set.options:
        o.is_primary = o.id == cmd.option_id

case AssignElementToOptionCmd():
    if (cmd.option_set_id is None) != (cmd.option_id is None):
        raise ValueError("optionSetId and optionId must both be null or both non-null")
    elem = els.get(cmd.element_id)
    if elem is None:
        raise ValueError(f"element not found: {cmd.element_id!r}")
    els[cmd.element_id] = elem.model_copy(update={"option_set_id": cmd.option_set_id, "option_id": cmd.option_id})

case SetViewOptionLockCmd():
    view = els.get(cmd.view_id)
    if view is None or not hasattr(view, "option_locks"):
        raise ValueError(f"viewId must reference a plan_view or viewpoint element")
    locks = dict(getattr(view, "option_locks") or {})
    if cmd.option_id is None:
        locks.pop(cmd.option_set_id, None)
    else:
        locks[cmd.option_set_id] = cmd.option_id
    els[cmd.view_id] = view.model_copy(update={"option_locks": locks})

        els.update(new_elements)
        return

    # In-place: mutate each element. Mirroring a wall flips its
    # parametric direction; alongT on hosted doors/windows is *not*
    # touched — the reversed start→end vector already places them at
    # the mirrored physical position.
    for tid in target_ids:
        el = els.get(tid)
        if el is None:
            continue
        mirrored = _mirror_one(el, cmd)
        if mirrored is not None:
            els[tid] = mirrored


def _mirror_one(el: Element, cmd: MirrorElementsCmd) -> Element | None:
    axis = cmd.axis
    if isinstance(el, WallElem):
        return _mirror_wall(el, axis)

    # command apply so create/update/delete of areas (and shafts that affect
    # `net` rule-set deductions) keep the value current.
    from bim_ai.area_calculation import recompute_all_areas

    recompute_all_areas(els)



